// Pre-hook: verifica env vars
const startedAt = new Date().toISOString();

const missingVars = [];
if (!$env.TELEGRAM_BOT_TOKEN) missingVars.push('TELEGRAM_BOT_TOKEN');
if (!$env.TELEGRAM_CHAT_ID) missingVars.push('TELEGRAM_CHAT_ID');
if (missingVars.length > 0) {
  throw new Error('Pre-hook FAIL — env vars mancanti: ' + missingVars.join(', '));
}

return [{ json: { startedAt, workflow: 'linkedin-safety-reminder', ok: true } }];

// Costruisce il promemoria settimanale anti-ban.
// Nota: questo workflow NON fa web scraping (Google blocca i bot).
// Per aggiornamenti manuali alle linee guida, aggiornare la skill /antiban-review.
const now = new Date();
const checkDate = now.toISOString().split('T')[0];
const weekNumber = Math.ceil((now.getDate() + new Date(now.getFullYear(), now.getMonth(), 1).getDay()) / 7);

return [{
  json: {
    checkDate,
    weekNumber,
    reminder: 'Max 80 azioni/giorno | IP residenziale | Delay variabile | Sessioni max 45min',
    links: [
      'https://getsales.io/blog/linkedin-automation-safety-guide-2026/',
      'https://growleads.io/blog/linkedin-automation-ban-risk-2026-safe-use/',
      'https://www.dux-soup.com/blog/linkedin-automation-safety-guide-how-to-avoid-account-restrictions-in-2026'
    ]
  }
}];

// Post-hook: logga completamento
const ts = new Date().toISOString();
const startedAt = $('Pre-hook: valida env').first().json.startedAt;
const durationMs = new Date(ts).getTime() - new Date(startedAt).getTime();
console.log(`[${ts}] linkedin-safety-reminder completato in ${durationMs}ms`);
return [{ json: { completedAt: ts, durationMs, status: 'ok' } }];
